import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useCart } from '../context/CartContext';

const Navbar = () => {
  const { user, logout } = useAuth();
  const { totalItems } = useCart();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <nav style={styles.nav}>
      <Link to="/" style={styles.brand}>🛒 MERN Shop</Link>

      <div style={styles.links}>
        <Link to="/" style={styles.link}>Home</Link>
        <Link to="/cart" style={styles.link}>
          Cart {totalItems > 0 && (
            <span style={styles.badge}>{totalItems}</span>
          )}
        </Link>

        {user ? (
          <>
            {user.isAdmin && (
              <Link to="/admin" style={styles.link}>Admin</Link>
            )}
            <Link to="/orders" style={styles.link}>My Orders</Link>
            <button onClick={handleLogout} style={styles.btn}>Logout</button>
          </>
        ) : (
          <>
            <Link to="/login" style={styles.link}>Login</Link>
            <Link to="/register" style={styles.link}>Register</Link>
          </>
        )}
      </div>
    </nav>
  );
};

const styles = {
  nav: {
    display: 'flex', justifyContent: 'space-between', alignItems: 'center',
    padding: '12px 24px', backgroundColor: '#1a1a2e', color: '#fff',
    position: 'sticky', top: 0, zIndex: 100,
  },
  brand: { color: '#e94560', fontSize: '22px', fontWeight: 'bold', textDecoration: 'none' },
  links: { display: 'flex', alignItems: 'center', gap: '16px' },
  link: { color: '#fff', textDecoration: 'none', fontSize: '15px' },
  btn: {
    background: '#e94560', color: '#fff', border: 'none',
    padding: '6px 14px', borderRadius: '6px', cursor: 'pointer',
  },
  badge: {
    background: '#e94560', color: '#fff', borderRadius: '50%',
    padding: '2px 7px', fontSize: '11px', marginLeft: '4px',
  },
};

export default Navbar;
